import React from 'react';
import { Swiper, SwiperSlide } from 'swiper/react';
import { Navigation, Pagination, Autoplay, EffectFade } from 'swiper/modules';

// Swiper stillerini içe aktar
import 'swiper/css';
import 'swiper/css/navigation';
import 'swiper/css/pagination';
import 'swiper/css/effect-fade';

const ModernSlider = () => {
  const slides = [
    {
      id: 1,
      title: "Geleceği Keşfedin",
      desc: "Modern arayüzler ve akıcı deneyimler.",
      bg: "bg-gradient-to-r from-indigo-500 to-purple-600"
    },
    {
      id: 2,
      title: "Hızlı ve Duyarlı",
      desc: "Tüm cihazlarda kusursuz performans.",
      bg: "bg-gradient-to-r from-emerald-500 to-teal-600"
    },
    {
      id: 3,
      title: "Esnek Yapı",
      desc: "Swiper.js ile sınırsız özelleştirme imkanı.",
      bg: "bg-gradient-to-r from-orange-500 to-rose-600"
    }
  ];

  return (
    <div className="w-full max-w-5xl mx-auto px-4 py-12">
      <Swiper
        // Kullanılacak modüller
        modules={[Navigation, Pagination, Autoplay, EffectFade]}
        
        // Temel Ayarlar
        spaceBetween={30}
        slidesPerView={1}
        loop={true}
        
        // Efekt (İstersen bunu silebilirsin, varsayılan 'slide'dır)
        effect={'fade'}
        
        // Otomatik Geçiş
        autoplay={{
          delay: 4000,
          disableOnInteraction: false,
        }}
        
        // Navigasyon ve Sayfalama
        navigation={true}
        pagination={{ 
          clickable: true,
          dynamicBullets: true 
        }}
        
        // Responsive Ayarlar (Kırılma Noktaları)
        breakpoints={{
          640: { slidesPerView: 1 },
          768: { slidesPerView: 1 },
          1024: { slidesPerView: 1 },
        }}
        className="rounded-2xl shadow-2xl overflow-hidden"
      >
        {slides.map((slide) => (
          <SwiperSlide key={slide.id}>
            <div className={`${slide.bg} h-[400px] flex flex-col items-center justify-center text-white p-8 text-center`}>
              <h2 className="text-4xl font-bold mb-4 drop-shadow-md">
                {slide.title}
              </h2>
              <p className="text-lg opacity-90 max-w-md">
                {slide.desc}
              </p>
              <button className="mt-8 px-6 py-2 bg-white text-gray-900 rounded-full font-semibold hover:bg-opacity-90 transition-all">
                Daha Fazla
              </button>
            </div>
          </SwiperSlide>
        ))}
      </Swiper>
      
      {/* Özel Stil Müdahalesi (Swiper oklarını ve noktalarını özelleştirmek için) */}
      <style jsx global>{`
        .swiper-button-next, .swiper-button-prev {
          color: white !important;
          transform: scale(0.7);
        }
        .swiper-pagination-bullet-active {
          background: white !important;
        }
      `}</style>
    </div>
  );
};

export default ModernSlider;
